#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; unsigned int K; // K is read but not used
        scanf("%d %u", &N, &K);
        uint64_t twoN = 1ULL << N;
        uint64_t ans = (twoN * twoN) - 3ULL * twoN + 2ULL;
        printf("%llu\n", ans);
    }
    return 0;
}

